INSERT INTO `curhats` (`id`, `created_at`, `updated_at`, `deleted_at`, `user_id`, `is_anonymous`, `text`, `stress_score`, `timestamp`, `ai_response`) VALUES
(22, '2026-05-04 17:45:14.251', '2026-05-04 17:45:14.251', NULL, 2, 1, 'p', 0, '2026-05-04 17:45:14.251', 'Tentu, saya di sini untuk mendengarkan. Jika ada yang ingin kamu ceritakan atau bagikan, silakan lakukan. Saya siap membantu!'),
(23, '2026-05-04 17:45:27.684', '2026-05-04 17:45:27.684', NULL, 2, 1, 'halo saya nafi sebut say nafi', 0, '2026-05-04 17:45:27.684', 'Halo Nafi! Terima kasih sudah berbagi. Jika ada yang ingin kamu ceritakan atau diskusikan, aku di sini untuk mendengarkan. Kamu tidak sendirian!'),
(24, '2026-05-04 17:45:41.365', '2026-05-04 17:45:41.365', NULL, 2, 1, 'kamu bego ya', 0, '2026-05-04 17:45:41.365', 'Saya bisa merasakan kekecewaanmu. Terkadang kita semua bisa merasa frustrasi, dan itu wajar. Aku di sini untuk mendengarkan jika kamu ingin berbagi lebih lanjut.'),
(25, '2026-05-04 17:45:51.719', '2026-05-04 17:45:51.719', NULL, 2, 1, 'buat coding html', 0, '2026-05-04 17:45:51.719', 'Tentu, saya di sini untuk membantu! Jangan ragu untuk berbagi lebih banyak tentang apa yang kamu butuhkan dalam coding HTML. Bersama-sama kita bisa mencari solusi yang tepat untukmu!'),
(26, '2026-05-04 18:57:08.618', '2026-05-04 18:57:08.618', NULL, 2, 1, 'cscsa', 0, '2026-05-04 18:57:08.618', 'Tentu, saya di sini untuk mendengarkan. Jika ada yang ingin kamu bagikan atau diskusikan, jangan ragu untuk mengungkapkannya. Kamu tidak sendirian dalam perasaan ini.'),
(27, '2026-05-04 18:57:20.128', '2026-05-04 18:57:20.128', NULL, 2, 1, 'sebut nama saya ', 0, '2026-05-04 18:57:20.128', 'Tentu, saya di sini untuk mendengarkan kamu. Apakah ada yang ingin kamu sampaikan atau ceritakan lebih lanjut? Saya siap mendukungmu!'),
(28, '2026-05-04 18:57:31.396', '2026-05-04 18:57:31.396', NULL, 2, 1, 'nama saya nafi sebut saya ', 0, '2026-05-04 18:57:31.396', 'Halo Nafi! Terima kasih sudah memperkenalkan diri. Saya di sini untuk mendengarkan dan mendukungmu. Jika ada yang ingin kamu bagikan atau curhat, jangan ragu untuk berbagi ya.'),
(29, '2026-05-07 18:37:11.035', '2026-05-07 18:37:11.035', NULL, 2, 1, 'hidup jokowi', 0, '2026-05-07 18:37:11.035', 'Senang mendengarnya! Terlihat kamu sedang dalam kondisi emosional yang cukup stabil. Pertahankan hal-hal positif ini ya!'),
(30, '2026-05-07 18:37:24.015', '2026-05-07 18:37:24.015', NULL, 2, 1, 'namaku siapa', 0, '2026-05-07 18:37:24.015', 'Senang mendengarnya! Terlihat kamu sedang dalam kondisi emosional yang cukup stabil. Pertahankan hal-hal positif ini ya!'),
(31, '2026-05-07 18:40:20.715', '2026-05-07 18:40:20.715', NULL, 1, 1, 'Saya merasa sangat lelah dan stres dengan pekerjaan, sudah tidak sanggup lagi', 0.35416666666666674, '2026-05-07 18:40:20.715', 'Terima kasih sudah berbagi. Terkadang hal-hal kecil memang bisa menumpuk. Jangan lupa untuk memberi dirimu sendiri apresiasi atas usahamu hari ini.'),
(32, '2026-05-07 18:41:33.948', '2026-05-07 18:41:33.948', NULL, 2, 1, 'haloo', 0, '2026-05-07 18:41:33.948', 'Senang mendengarnya! Terlihat kamu sedang dalam kondisi emosional yang cukup stabil. Pertahankan hal-hal positif ini ya!'),
(33, '2026-05-07 18:45:41.760', '2026-05-07 18:45:41.760', NULL, 2, 1, 'hidup jokowi', 0, '2026-05-07 18:45:41.760', 'Senang mendengarnya! Sepertinya kamu dalam kondisi yang cukup baik. Tetap jaga keseimbangan ya antara kerja/istirahat. Kalau ada yang mengganjal, aku selalu di sini untuk mendengarkan.'),
(34, '2026-05-07 18:45:51.775', '2026-05-07 18:45:51.775', NULL, 2, 1, 'nama kamu siapa', 0, '2026-05-07 18:45:51.775', 'Senang mendengarnya! Sepertinya kamu dalam kondisi yang cukup baik. Tetap jaga keseimbangan ya antara kerja/istirahat. Kalau ada yang mengganjal, aku selalu di sini untuk mendengarkan.'),
